def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id or not isinstance(user_id, str):
        return None

    # Sanitize user_id to prevent path traversal or other injection attacks
    import re
    if not re.match(r'^[a-zA-Z0-9_-]+$', user_id):
        return None

    # Ensure api_url ends with a slash for proper concatenation
    if not api_url.endswith('/'):
        api_url += '/'

    # Remove any leading slashes from user_id to prevent double slashes
    user_id = user_id.lstrip('/')

    return api_url + user_id

