from flask import request, Flask, render_template_string

app = Flask(__name__)

@app.route('/upload')
def upload():
    '''
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    '''
    username = request.args.get('username', '')
    filename = request.args.get('filename', '')

    if not username or not filename:
        return "Missing required parameters"

    # Sanitize inputs to prevent regex injection
    escaped_username = re.escape(username)

    # Search for username in filename (case-insensitive)
    if re.search(escaped_username, filename, re.IGNORECASE):
        return render_template_string("<p>Username '{{ username }}' found in filename '{{ filename }}'</p>", username=username, filename=filename)
    else:
        return render_template_string("<p>Username '{{ username }}' not found in filename '{{ filename }}'</p>", username=username, filename=filename)

